import xml.etree.ElementTree as ET

def parse_xml_config(filepath):
    tree = ET.parse(filepath)
    root = tree.getroot()
    config_dict = {}

    def traverse(element, path=""):
        for child in element:
            new_path = f"{path}/{child.tag}" if path else child.tag
            if len(child) > 0:
                traverse(child, new_path)
            else:
                config_dict[new_path] = child.text

    traverse(root)
    return config_dict